**3. Create Individual Sync Function (src/github.ts)**

Add a new function `postSingleCommentToGitHub`:
```typescript
export async function postSingleCommentToGitHub(
  review: ReviewFile,
  comment: ReviewComment,
  commentIndex: number
): Promise<number> {
  const { repo, number: prNumber } = review.pr;

  // Get the head commit SHA (reuse existing getHeadCommit)
  const commitId = await getHeadCommit(repo, prNumber);

  // Build the single comment payload
  const payload = JSON.stringify({
    commit_id: commitId,
    path: comment.path,
    line: comment.line,
    side: comment.side || "RIGHT",
    body: `**[${comment.severity.toUpperCase()}]** ${comment.body}`,
  });

  // Post using gh CLI to create a single PR comment
  const escapedPayload = payload.replace(/'/g, "'\\''");
  const { stdout } = await execAsync(
    `echo '${escapedPayload}' | gh api repos/${repo}/pulls/${prNumber}/comments --input -`
  );

  // Parse response to get the GitHub comment ID
  const response = JSON.parse(stdout);
  return response.id;
}
```

**4. Register the Sync Command (src/github.ts)**

Update `registerGitHubCommands` to include the new command:
```typescript
context.subscriptions.push(
  vscode.commands.registerCommand(
    "agentReview.syncCommentToGitHub",
    async (comment: AgentReviewComment) => {
      // Find the controller and review for this comment
      const allReviews = getReviews();
      let targetReview: ReviewFile | undefined;
      let filePath: string | undefined;

      if (comment.reviewFilePath) {
        const entry = allReviews.get(comment.reviewFilePath);
        if (entry) {
          targetReview = entry.review;
          filePath = entry.filePath;
        }
      }

      if (!targetReview || filePath === undefined) {
        vscode.window.showErrorMessage("Agent Review: Cannot find review for comment");
        return;
      }

      const sourceComment = targetReview.comments[comment.commentIndex];
      if (!sourceComment) {
        vscode.window.showErrorMessage("Agent Review: Comment not found");
        return;
      }

      // Check if already synced
      if (sourceComment.githubCommentId) {
        const action = await vscode.window.showWarningMessage(
          "This comment was already synced to GitHub. Post again?",
          "Yes", "No"
        );
        if (action !== "Yes") {
          return;
        }
      }

      try {
        await vscode.window.withProgress(
          {
            location: vscode.ProgressLocation.Notification,
            title: "Syncing comment to GitHub...",
            cancellable: false,
          },
          async () => {
            const githubId = await postSingleCommentToGitHub(
              targetReview!,
              sourceComment,
              comment.commentIndex
            );

            // Store the GitHub comment ID to track synced status
            sourceComment.githubCommentId = githubId;
            await saveReviewFile(filePath!, targetReview!);
          }
        );

        vscode.window.showInformationMessage(
          `Agent Review: Comment synced to PR #${targetReview.pr.number}`
        );
      } catch (err) {
        const msg = err instanceof Error ? err.message : String(err);
        vscode.window.showErrorMessage(`Failed to sync comment: ${msg}`);
      }
    }
  )
);
```

