**Key Considerations:**

- The GitHub API `POST /repos/{owner}/{repo}/pulls/{prNumber}/comments` creates individual review comments
- Include severity in the comment body since GitHub doesn't have a native severity concept
- Store `githubCommentId` to prevent accidental duplicate posts and enable future features like editing/deleting synced comments
- The isSaving flag pattern from `ReviewCommentController` should be respected when saving the review file to prevent file watcher loops

Implement a VSCode TreeDataProvider and TreeView with two distinct sections for reviewed and pending PRs:

**1. Create new file `src/prOverview.ts`:**

Define the TreeDataProvider with two sections:

```typescript
import * as vscode from "vscode";
import { ReviewFile, Severity } from "./parser";

type TreeItemType = "section" | "repo" | "pr" | "file" | "comment";

export interface PendingPR {
  repo: string;
  number: number;
  title: string;
  author: string;
  createdAt: string; // ISO date for age calculation
}

export class PROverviewItem extends vscode.TreeItem {
  constructor(
    public readonly label: string,
    public readonly collapsibleState: vscode.TreeItemCollapsibleState,
    public readonly type: TreeItemType,
    public readonly reviewFilePath?: string,
    public readonly repoName?: string,
    public readonly pendingPR?: PendingPR
  ) {
    super(label, collapsibleState);
  }
}

export class PROverviewProvider implements vscode.TreeDataProvider<PROverviewItem> {
  private _onDidChangeTreeData = new vscode.EventEmitter<PROverviewItem | undefined>();
  readonly onDidChangeTreeData = this._onDidChangeTreeData.event;

  private reviews: Map<string, { review: ReviewFile; filePath: string }> = new Map();
  private pendingPRs: PendingPR[] = [];
  private pendingError: string | null = null;
  private isLoading = false;

  refresh(): void {
    this._onDidChangeTreeData.fire(undefined);
  }

  updateReviews(reviews: Map<string, { review: ReviewFile; filePath: string }>): void {
    this.reviews = reviews;
    this.refresh();
  }

  setPendingPRs(prs: PendingPR[]): void {
    this.pendingPRs = prs;
    this.pendingError = null;
    this.refresh();
  }

  setPendingError(error: string): void {
    this.pendingError = error;
    this.pendingPRs = [];
    this.refresh();
  }

  setLoading(loading: boolean): void {
    this.isLoading = loading;
    this.refresh();
  }

  getTreeItem(element: PROverviewItem): vscode.TreeItem {
    return element;
  }

  getChildren(element?: PROverviewItem): PROverviewItem[] {
    if (!element) {
      // Root level: show sections
      return this.getSections();
    }
    if (element.type === "section") {
      return element.label === "Reviewed" 
        ? this.getReviewedRepoItems() 
        : this.getPendingRepoItems();
    }
    if (element.type === "repo") {
      return element.label === "Reviewed" || this.isReviewedRepo(element.repoName!)
        ? this.getReviewedPRsForRepo(element.repoName!)
        : this.getPendingPRsForRepo(element.repoName!);
    }
    return [];
  }

  private getSections(): PROverviewItem[] { /* ... */ }
  private getReviewedRepoItems(): PROverviewItem[] { /* ... */ }
  private getPendingRepoItems(): PROverviewItem[] { /* ... */ }
  private getReviewedPRsForRepo(repo: string): PROverviewItem[] { /* ... */ }
  private getPendingPRsForRepo(repo: string): PROverviewItem[] { /* ... */ }
}
```

