**8. Age Formatting Helper:**
```typescript
function formatAge(createdAt: string): string {
  const created = new Date(createdAt);
  const now = new Date();
  const diffMs = now.getTime() - created.getTime();
  const days = Math.floor(diffMs / (1000 * 60 * 60 * 24));
  if (days === 0) return "today";
  if (days === 1) return "1 day ago";
  return `${days} days ago`;
}
```

**9. Auto-refresh Logic in `extension.ts`:**

```typescript
import { PROverviewProvider, fetchPendingReviewPRs } from "./prOverview";

const prOverviewProvider = new PROverviewProvider();
let refreshInterval: ReturnType<typeof setInterval> | undefined;
let panelVisible = false;

// Register TreeView with visibility tracking
const treeView = vscode.window.createTreeView("agentReview.prOverview", {
  treeDataProvider: prOverviewProvider,
  showCollapseAll: true,
});

treeView.onDidChangeVisibility((e) => {
  panelVisible = e.visible;
  if (e.visible) {
    refreshPendingPRs();
    startRefreshInterval();
  } else {
    stopRefreshInterval();
  }
});

function startRefreshInterval(): void {
  stopRefreshInterval();
  refreshInterval = setInterval(refreshPendingPRs, 15 * 60 * 1000); // 15 minutes
}

function stopRefreshInterval(): void {
  if (refreshInterval) {
    clearInterval(refreshInterval);
    refreshInterval = undefined;
  }
}

async function refreshPendingPRs(): Promise<void> {
  prOverviewProvider.setLoading(true);
  try {
    const prs = await fetchPendingReviewPRs();
    prOverviewProvider.setPendingPRs(prs);
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : String(err);
    prOverviewProvider.setPendingError(msg);
  } finally {
    prOverviewProvider.setLoading(false);
  }
}

// Register refresh command
context.subscriptions.push(
  vscode.commands.registerCommand("agentReview.refreshPROverview", async () => {
    await loadAllReviews(context.extensionUri);
    await refreshPendingPRs();
  })
);

// Update provider after loadAllReviews()
const allReviews = new Map<string, { review: ReviewFile; filePath: string }>();
for (const [filePath, ctrl] of controllers) {
  const review = ctrl.getReview();
  if (review) {
    allReviews.set(filePath, { review, filePath });
  }
}
prOverviewProvider.updateReviews(allReviews);
```

