**11. Severity Count Formatting:**
```typescript
function formatSeverityCounts(comments: ReviewComment[]): string {
  const counts: Partial<Record<Severity, number>> = {};
  for (const c of comments) {
    counts[c.severity] = (counts[c.severity] || 0) + 1;
  }
  // Display order: blocking, important, suggestion, nit, praise, learning
  const parts: string[] = [];
  if (counts.blocking) parts.push(`${counts.blocking} blocking`);
  if (counts.important) parts.push(`${counts.important} important`);
  if (counts.suggestion) parts.push(`${counts.suggestion} suggestion`);
  if (counts.nit) parts.push(`${counts.nit} nit`);
  if (counts.praise) parts.push(`${counts.praise} praise`);
  if (counts.learning) parts.push(`${counts.learning} learning`);
  return parts.join(" · ");
}
```
